class Solution:
    def distinctDifferenceArray(self, nums):
        n = len(nums)
        diff = []
        for i in range(n):
            prefix = len(set(nums[:i + 1]))
            suffix = len(set(nums[i + 1:]))
            diff.append(prefix - suffix)
        return diff

