class Solution:
    def distinctDifferenceArray(self, nums: List[int]) -> List[int]:
        n = len(nums)
        suffix_count = {}
        for v in nums:
            suffix_count[v] = suffix_count.get(v, 0) + 1
        prefix_seen = set()
        diff = []
        for i in range(n):
            v = nums[i]
            suffix_count[v] -= 1
            if suffix_count[v] == 0:
                del suffix_count[v]
            prefix_seen.add(v)
            diff.append(len(prefix_seen) - len(suffix_count))
        return diff

