var distinctDifferenceArray = function(nums) {
    const n = nums.length;
    const suffixCount = new Map();
    for (const v of nums) {
        suffixCount.set(v, (suffixCount.get(v) || 0) + 1);
    }
    const prefixSeen = new Set();
    const diff = [];
    for (let i = 0; i < n; i++) {
        const v = nums[i];
        const c = suffixCount.get(v) - 1;
        if (c === 0) {
            suffixCount.delete(v);
        } else {
            suffixCount.set(v, c);
        }
        prefixSeen.add(v);
        diff.push(prefixSeen.size - suffixCount.size);
    }
    return diff;
};
